PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?film ?filmLabel ?metacriticScore ?rottenTomatoesScore WHERE {
  VALUES ?film {
    wd:Q217020 wd:Q1201853 wd:Q65768604
  }
  ?film rdfs:label ?filmLabel .
  FILTER(LANG(?filmLabel) = "en")
  OPTIONAL {
    ?film wdt:P444 ?metacriticScore .
    ?film wdt:P447 wd:Q250259
  }
  OPTIONAL {
    ?film wdt:P444 ?rottenTomatoesScore .
    ?film wdt:P447 wd:Q1264329
  }
}

