  FILTER (LANG(?filmLabel) = "en")
  FILTER (CONTAINS(LCASE(?filmLabel), "thor"))
  OPTIONAL { ?film wdt:P1712 ?metacriticScore }
  OPTIONAL { ?film wdt:P1258 ?rottenTomatoesScore }
  FILTER (BOUND(?metacriticScore) || BOUND(?rottenTomatoesScore))
